recommendedContract.inputType:
type BuildStructuredTableViewModelInput = {
  rows: ReadonlyArray<Record<string, unknown>>;
  displayCols: ReadonlyArray<{
    key: string;
    labelKo: string;
  }>;
  emptyValue?: string; // default "-"
};

recommendedContract.outputType:
type StructuredTableColumn = {
  key: string;
  label: string;
  index: number;
  align: "left" | "center" | "right";
  width: string;
  isNumeric: boolean;
  isIndex: boolean;
};

type StructuredTableCell = {
  key: string;
  label: string;
  value: string;
  displayValue: string;
  isEmpty: boolean;
  align: "left" | "center" | "right";
  columnIndex: number;
  rowIndex: number;
};

type StructuredTableRow = {
  index: number;
  sourceRow: Record<string, unknown>;
  cells: StructuredTableCell[];
};

type StructuredTableViewModel = {
  columns: StructuredTableColumn[];
  rows: StructuredTableRow[];
  meta: {
    rowCount: number;
    columnCount: number;
    hasRows: boolean;
    hasColumns: boolean;
    hasEmptyCells: boolean;
  };
};
